import React, { useState } from 'react';

const App = () => {
  const [login, setLogin] = useState('');
  const [credit, setCredit] = useState(0);
  const [showCredit, setShowCredit] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
  };

  const handleToggle = () => {
    setShowCredit(!showCredit);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white p-4 shadow-md rounded-md w-96">
        <h2 className="text-2xl text-center my-4">AI Model Credit Tracker</h2>
        <form onSubmit={handleSubmit}>
          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2" for="login">Login:</label>
            <input className="shadow appearance-none border rounded-w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline" id="login" type="text" placeholder="Login" value={login} onChange={(e) => setLogin(e.target.value)} />
          </div>
          <button className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded">Submit</button>
        </form>
        <div className="my-4">
          <button className="bg-orange-500 hover:bg-orange-700 text-white font-bold py-2 px-4 rounded" onClick={handleToggle}>Toggle Credit</button>
        </div>
        <div className={showCredit ? 'block' : 'hidden'}>
          <div className="flex items-center justify-center my-4">
            <div className="bg-yellow-500 p-4 text-white rounded-md">
              <p className="text-2xl">$<span className="text-4xl">{credit}</span></p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
